boot.widget:
// 上游基底 CSS 硬写 document.head;动态导入后把本次 .jse-* style 移入 shadow(铁律 2)
const before = new Set(document.head.querySelectorAll('style'));
const { createJSONEditor } = await import('https://cdn.jsdelivr.net/npm/vanilla-jsoneditor@3/+esm?ov-shadow=' + crypto.randomUUID());
const css = [...document.head.querySelectorAll('style')].filter((s) => !before.has(s) && s.textContent.includes('.jse-')); shadowRoot.append(...css);
const el = document.createElement('div'); el.style.height = `${spec.height ?? 520}px`; shadowRoot.appendChild(el);
const editor = createJSONEditor({ target: el, props: { content: data.content, mode: data.mode ?? 'tree', readOnly: data.readOnly ?? false, mainMenuBar: data.mainMenuBar ?? true, navigationBar: data.navigationBar ?? true, statusBar: data.statusBar ?? true, indentation: data.indentation ?? 2 } });

